import React, { useState, useEffect } from 'react';

const App = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filterTerm, setFilterTerm] = useState('');
  const [contentItems, setContentItems] = useState([]);

  useEffect(() => {
    // Fetch content items from API
    setContentItems([...]);
  }, []);

  const handleSearch = (e) => {
    setSearchTerm(e.target.value);
  };

  const handleFilter = (e) => {
    setFilterTerm(e.target.value);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="flex flex-col items-center">
        <input type="text" className="bg-[#B7D7CD] text-black py-2 px-4 rounded-lg" placeholder="Search" value={searchTerm} onChange={handleSearch} />
        <select className="bg-[#C06C88] text-white py-2 px-4 rounded-lg" value={filterTerm} onChange={handleFilter}>
          <option value="">Select Category</option>
          <option value="Category 1">Category 1</option>
          <option value="Category 2">Category 2</option>
        </select>
        <table className="bg-[#411C56] text-white border-collapse collapse w-full">
          <thead>
            <tr>
              <th>ID</th>
              <th>Title</th>
            </tr>
          </thead>
          <tbody>
            {contentItems.map((item, index) => (
              <tr key={index}>
                <td>{item.id}</td>
                <td>{item.title}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default App;
